172→                    </g>
173→                </g>
174→            </svg>),
175→            className: 'bookmark-button',
176→            bookmarkAction: (e, journalId) => {
177→                e.preventDefault();
178→                e.stopPropagation();
179→                debounceClickBookmark(journalId);
180→            },
181→            countBookmarks: (count) => <p  style={{padding: '0', margin: '0', fontSize: '0.78rem'}}>{formatCounts(count)}</p>
182→        },
183→        {
184→            iconCount: (count) => <p style={{padding: '0', margin: '0', fontSize: '0.6rem', color: "var(--icon-view-count)"}}>{formatCounts(count)}</p>,
185→            iconView:
186→            <svg xmlns="http://www.w3.org/2000/svg" fill="var(--icon-view)" width="28px" height="28px" viewBox="-3.5 0 32 32" version="1.1">
187→                <title>view</title>
188→                <path d="M12.406 13.844c1.188 0 2.156 0.969 2.156 2.156s-0.969 2.125-2.156 2.125-2.125-0.938-2.125-2.125 0.938-2.156 2.125-2.156zM12.406 8.531c7.063 0 12.156 6.625 12.156 6.625 0.344 0.438 0.344 1.219 0 1.656 0 0-5.094 6.625-12.156 6.625s-12.156-6.625-12.156-6.625c-0.344-0.438-0.344-1.219 0-1.656 0 0 5.094-6.625 12.156-6.625zM12.406 21.344c2.938 0 5.344-2.406 5.344-5.344s-2.406-5.344-5.344-5.344-5.344 2.406-5.344 5.344 2.406 5.344 5.344 5.344z"/>
189→            </svg>,
190→
191→        }
192→    ]
193→
194→    const userId = user?.userData?.[0]?.id || null;
195→    const isSearchMode = committedSearchQuery.length >= 2;
196→
197→    useEffect(() => {
198→        const timer = setTimeout(() => {
199→            setDebouncedSearchInput(searchInput.trim());
200→        }, 350);
201→
202→        return () => clearTimeout(timer);
203→    }, [searchInput]);
204→
205→    const {
206→        data,
207→        fetchNextPage,
208→        hasNextPage,
209→        isFetchingNextPage,
210→        isLoading: isFeedLoading,
211→    } = useInfiniteQuery({
212→        queryKey: ['journals', userId],
213→        queryFn: ({pageParam = null}) => getJournals(pageParam, 5, userId),
214→        getNextPageParam: (lastPage) => {
215→            if(lastPage?.hasMore) {
216→                const lastJournal = lastPage?.data[lastPage?.data?.length - 1]; //get the last array of object using index
217→                return new Date(lastJournal.created_at).toISOString();
218→            }
219→            return undefined;
220→        } ,
221→        refetchOnWindowFocus: false
222→    })
223→
224→    const {
225→        data: searchData,
226→        isLoading: isSearchLoading,
227→        isFetching: isSearchFetching,
228→        error: searchError,
229→    } = useQuery({
230→        queryKey: ['journals-search', userId, committedSearchQuery],
231→        queryFn: () => searchJournals(committedSearchQuery, 10, userId),
232→        enabled: isSearchMode,
233→        refetchOnWindowFocus: false,
234→        staleTime: 15 * 1000,
235→    });
236→
237→    const {
238→        data: suggestionData,
239→        isLoading: isSuggestionsLoading,
240→    } = useQuery({
241→        queryKey: ['journals-suggestions', userId, debouncedSearchInput],
242→        queryFn: () => searchJournals(debouncedSearchInput, 6, userId),
243→        enabled: debouncedSearchInput.length >= 2 && isSearchFocused,
244→        refetchOnWindowFocus: false,
245→        staleTime: 10 * 1000,
246→    });
247→
248→    const handleClickSettings = (e, postId) =>{
249→        e.stopPropagation();
250→        setPostIdSettings(postId === postIdSettings ? null : postId)
251→    }
252→
253→    const mutationLike = useLikeMutation(session, user?.userData?.[0]?.id);
254→
255→    const handleClickLike = async (journalId, receiverId) => {
256→        if(!session) return openAuthModal();
257→        console.log(journalId)
258→        mutationLike.mutate({journalId, receiverId}) //passing this into mutationFn {journalId: the id}
259→    }
260→
261→
262→    const mutationBookmark = useBookMarkMutation(session, userId);
263→
264→    const handleClickBookmark = async (journalId) => {
265→        if(!session) return openAuthModal();
266→        console.log(journalId)
267→        // mutationBookmark.mutate({journalId});
268→        const response = await mutationBookmark.mutateAsync({journalId})
269→
270→        if(timeOutRef.current){
271→            clearTimeout(timeOutRef.current);
272→        }
273→        if(response.message === 'success'){
274→            setBookmarkedMessage('Post was added to your Bookmarks')
275→            setShowBookmarkedMessage(journalId);
276→            timeOutRef.current = setTimeout(() =>{
277→                setShowBookmarkedMessage(null)
278→                setBookmarkedMessage('')
279→            }, 2500)
280→        } else {
281→            setBookmarkedMessage('Post was removed from your Bookmarks')
282→            setShowBookmarkedMessage(journalId);
283→            timeOutRef.current = setTimeout(() =>{
284→                setShowBookmarkedMessage(null)
285→                setBookmarkedMessage('')
286→            }, 2500)
287→        }
288→        console.log(response.message);
289→    }
290→
291→    const debounceClickBookmark = debounce(handleClickBookmark, 100);
292→
293→    const handleSubmitSearch = (rawQuery) => {
294→        const normalizedQuery = typeof rawQuery === 'string' ? rawQuery.trim() : '';
295→        if(normalizedQuery.length < 2){
296→            setCommittedSearchQuery('');
297→            return;
298→        }
299→
300→        setCommittedSearchQuery(normalizedQuery);
301→        setSearchInput(normalizedQuery);
302→        setIsSearchFocused(false);
303→    };
304→
305→    const handleClearSearch = () => {
306→        setSearchInput('');
307→        setDebouncedSearchInput('');
308→        setCommittedSearchQuery('');
309→        setIsSearchFocused(false);
310→    };
311→
312→    const handleSearchInputKeyDown = (e) => {
313→        if(e.key === 'Enter'){
314→            e.preventDefault();
315→            handleSubmitSearch(searchInput);
316→        }
317→
318→        if(e.key === 'Escape'){
319→            setIsSearchFocused(false);
320→        }
321→    };
322→
323→    const handleClickSuggestion = (journal) => {
324→        if(!journal?.id){
325→            return;
326→        }
327→        setIsSearchFocused(false);
328→        if(journal?.title){
329→            setSearchInput(journal.title);
330→            setDebouncedSearchInput(journal.title);
331→        }
332→        navigate(`/home/post/${journal.id}`);
333→    };
334→
335→    const handleVisitFreedomWall = () => {
336→        navigate('/home/freedom-wall');
337→    };
338→
339→    useEffect(() => {
340→        const handleOutsideSearchClick = (e) => {
341→            if(searchShellRef.current && !searchShellRef.current.contains(e.target)){
342→                setIsSearchFocused(false);
343→            }
344→        };
345→
346→        window.addEventListener('mousedown', handleOutsideSearchClick);
347→        return () => window.removeEventListener('mousedown', handleOutsideSearchClick);
348→    }, []);
349→
350→    useEffect(() =>{
351→        if(!isSearchMode && inView && hasNextPage && !isFetchingNextPage) {
352→            fetchNextPage();
353→        }
354→    }, [inView, fetchNextPage, hasNextPage, isFetchingNextPage, isSearchMode])
355→
356→
357→    useEffect(() => {
358→       const handleClickOutside = (e) =>{
359→        if(modalRef.current && !modalRef.current.contains(e.target)){
360→            setPostIdSettings(null)
361→        }
362→       }
363→       window.addEventListener('click', handleClickOutside)
364→
365→       return() => {
366→        window.removeEventListener('click', handleClickOutside)
367→       }
368→    }, [])
369→
370→    useEffect(() =>{
371→        const scroll = (e) =>{
372→            setShowHeaders(!showHeaders)
373→
374→            if(timeOutRef.current){
375→                clearTimeout(timeOutRef.current);
376→            }
377→            timeOutRef.current = setTimeout(() => {
378→                setShowHeaders(showHeaders)
379→            }, 100);
380→        }
381→        document.addEventListener('scroll', scroll, true);
382→        return() =>{
383→            if(timeOutRef.current){
384→                clearTimeout(timeOutRef.current);
385→            }
386→            document.removeEventListener('scroll', scroll, true)
387→        }
388→    }, [])
389→
390→    const feedJournals = data?.pages?.flatMap((page) => page.data || []) || [];
391→    const searchedJournals = searchData?.data || [];
392→    const suggestionItems = suggestionData?.data || [];
393→    const journals = isSearchMode ? searchedJournals : feedJournals;
394→    const isLoading = isSearchMode ? isSearchLoading : isFeedLoading;
395→    const showSuggestions = isSearchFocused && debouncedSearchInput.length >= 2;
396→
397→    if(isLoading) {
398→        return(
399→            <>
400→            <div className="postcards-parent-loading-container">
401→                <MoonLoader loading={isLoading} color="var(--loader-color)" speedMultiplier={1} size={20}/>
402→            </div>
403→            </>
404→        )
405→    }
406→
407→    return(
408→        <>
409→        <div className="mobile-top-header">
410→            <span className="mobile-brand-text">iskrib</span>
411→            {clickOpenSidebar && (
412→                <button className="mobile-header-profile-btn" onClick={clickOpenSidebar}>
413→                    <img src={user?.userData?.[0]?.image_url || '/assets/profile.jpg'} alt="profile" />
414→                </button>
415→            )}
416→        </div>
417→
418→        <div className="search-shell" ref={searchShellRef}>
419→        <div className="search-top-bar">
420→            <div className="search-input-wrap">
421→                <svg className="search-icon" xmlns="http://www.w3.org/2000/svg" viewBox="0 0 24 24" fill="currentColor" aria-hidden="true">
422→                    <path d="M10 2a8 8 0 1 0 4.906 14.32l4.387 4.387a1 1 0 0 0 1.414-1.414L16.32 14.906A8 8 0 0 0 10 2Zm0 2a6 6 0 1 1 0 12a6 6 0 0 1 0-12Z"/>
423→                </svg>
424→                <input
425→                    type="search"
426→                    value={searchInput}
427→                    onChange={(e) => setSearchInput(e.target.value)}
428→                    onFocus={() => setIsSearchFocused(true)}
429→                    onKeyDown={handleSearchInputKeyDown}
430→                    placeholder="Search writings by meaning or title..."
431→                    className="search-input"
432→                    aria-label="Search journals"
433→                />
434→            </div>
435→            {searchInput ? (
436→                <button type="button" className="search-clear-btn" onClick={handleClearSearch}>
437→                    Clear
438→                </button>
439→            ) : null}
440→            <button type="button" className="search-freedom-wall-btn" onClick={handleVisitFreedomWall}>
441→                Visit Freedom Wall
442→            </button>
443→            {handleOpenTextEditor && (
